function moveCard(columns, cardId, fromCol, toCol) {
  const card = columns[fromCol].find(c => c.id === cardId);
  columns[fromCol] = columns[fromCol].filter(c => c.id !== cardId);
  columns[toCol] = [...columns[toCol], card];
  return columns;
}

